function metrics(build=state.builder){const m=byId(builderCatalogue.meats,build.meat),c=byId(builderCatalogue.cheeses,build.cheese),bun=byId(builderCatalogue.buns,build.bun),s=byId(builderCatalogue.sauces,build.sauce),t=builderCatalogue.toppings[build.toppings]||builderCatalogue.toppings.standard,on=aromatic("onions",build.onion),ga=aromatic("garlics",build.garlic),se=aromatic("seasonings",build.seasoning),f=build.weight/100,rawFat=m.fat100*f+c.fat+bun.fat+s.fat+t.fat+on.fat+ga.fat+se.fat,rawProtein=m.protein100*f+c.protein+bun.protein+s.protein+t.protein+on.protein+ga.protein+se.protein,rawCarbs=m.carbs100*f+c.carbs+bun.carbs+s.carbs+t.carbs+on.carbs+ga.carbs+se.carbs,rawCalories=m.kcal100*f+c.kcal+bun.kcal+s.kcal+t.kcal+on.kcal+ga.kcal+se.kcal,cookedPattyWeight=Math.round(build.weight*m.yield),lostFat=m.fat100*f*(1-m.fatRetention),cookedFat=Math.max(0,rawFat-lostFat),cookedCalories=Math.max(0,rawCalories-lostFat*9),td=Number(build.thickness)-16,ar=k=>(on[k]||0)+(ga[k]||0)+(se[k]||0),scores={juiciness:clamp(Math.round(m.scores.juiciness+clamp(td*.75,-8,10)+s.moisture*.6+ar("juiciness")),0,100),tenderness:clamp(Math.round(m.scores.tenderness-Math.max(td,0)*.25+ar("tenderness")),0,100),beefiness:clamp(m.scores.beefiness+ar("beefiness"),0,100),richness:clamp(Math.round(m.scores.richness+c.richness+s.moisture*.25+ar("richness")),0,100),crust:clamp(Math.round(m.scores.crust+clamp(-td*1.2,-15,16)+ar("crust")),0,100),structure:clamp(Math.round(m.scores.structure+bun.structure+c.structure-s.moisture*.45+ar("structure")),0,100)};return {m,c,bun,s,t,on,ga,se,raw:{calories:rnd(rawCalories),protein:rnd(rawProtein,1),fat:rnd(rawFat,1),carbs:rnd(rawCarbs,1)},cooked:{calories:rnd(cookedCalories),protein:rnd(rawProtein*.98,1),fat:rnd(cookedFat,1),carbs:rnd(rawCarbs,1),pattyWeight:cookedPattyWeight},density:rnd((rawProtein*.98)/cookedCalories*100,1),scores,overall:Math.round(Object.values(scores).reduce((a,b)=>a+b,0)/6)};}
