if(key==="meat"){title=`${n.m.label}: ${n.m.flavour.split("\u2014")[0].split(".")[0].toLowerCase()}`;flavour=n.m.flavour+` Juiciness ${sign(dj)}, crust ${sign(dc)} on the eating-experience bars.`;technique=n.m.cooking;}
if(key==="weight"){const w=Number(next.weight);title=w>Number(prev.weight)?"A heavier, meatier bite":"A lighter, more balanced bite";flavour=w>=200?"At this weight the patty dominates every bite \u2014 bun and toppings become supporting cast.":w<=120?"A lighter patty lets the bun, sauce and toppings share the stage with the beef.":"This weight keeps meat and bun in classic balance \u2014 each bite carries both.";technique=`${w} g at this thickness means ${cookGuidance(next.thickness)}.`;}
