function adaptRecipe(id,type){const recipe=recipeById(id);if(!recipe)return;state.builder={...state.builder,...recipe.build};if(type==="protein")Object.assign(state.builder,{meat:"beef90",cheese:"lightcheddar",bun:"thin",sauce:"yoghurt"});if(type==="calories")Object.assign(state.builder,{meat:"beef90",weight:Math.min(state.builder.weight,140),cheese:"none",bun:"lettuce",sauce:"mustard"});if(type==="moisture")Object.assign(state.builder,{meat:state.builder.meat==="beef90"?"beef85":state.builder.meat,sauce:"yoghurt",thickness:Math.max(state.builder.thickness,16)});if(type==="crust")Object.assign(state.builder,{thickness:Math.min(state.builder.thickness,10),bun:"potato"});state.builder.name=`${recipe.title} · ${type}`;save();route("builder");}

