function sidesSection(){return `<section class="section recipe-section"><div class="section-head"><div><h2>Condiments &amp; sides</h2><p>Caramelised onions, chili con carne, baked garlic and more — the supporting cast that makes a burger complete</p></div></div>${sideCards()}</section>`;}
