// RC2-M16: the complete six-recipe collection is reachable from Home with clear cook-vs-adapt guidance.
function fullCollectionSection(){return `<section class="section recipe-section"><div class="section-head"><div><h2>The complete collection</h2><p>All six cook-alongs — open one to cook it step by step, or adapt any of them in the Builder afterwards</p></div></div>${recipeCards(6)}</section>`;}
function completeRecipe(recipe){if(!state.completedRecipes.some(item=>item.id===recipe.id))state.completedRecipes.push({id:recipe.id,title:recipe.title,completedAt:new Date().toISOString(),macros:recipe.macros});state.builder={...state.builder,...recipe.build};delete state.recipeProgress[recipe.id];save();}
function openRecipe(id){const recipe=recipeById(id);if(!recipe)return;openRecipeStory(recipe);}
// v1.2.0: compile the current Builder selections into a personalised cook-along and open it. Regenerating always resets any stale progress for the previous custom story.
function openCookBuild(){const story=generateCookStory(state.builder,builderCatalogue,metrics());delete state.recipeProgress[story.id];save();openRecipeStory(story,{custom:true});}
// v1.2.0: the story viewer now accepts a recipe object directly, so generated cook-along stories share the exact same infrastructure (progress, wake lock, layers, swipe).
function openRecipeStory(recipe,opts={}){const saved_pos=state.recipeProgress[recipe.id];const overview={image:recipe.hero,kicker:`${recipe.collection} · ${recipe.time} · ${recipe.difficulty}`,title:recipe.title,body:"",overview:true};const slides=[overview,...recipe.steps];let index=0,last=0,sx=0,sy=0,tracking=false;const viewer=document.createElement("section");viewer.className="story recipe-story";const layer=pushLayer(()=>{teardown();render();});acquireWakeLock();const timer={left:0,total:0,label:"",running:false,done:false,iv:null};const stopTimer=()=>{if(timer.iv){clearInterval(timer.iv);timer.iv=null;}timer.running=false;};const clearTimer=()=>{stopTimer();timer.left=0;timer.total=0;timer.label="";timer.done=false;};const fmtT=s=>`${Math.floor(s/60)}:${String(s%60).padStart(2,"0")}`;const parseTimer=text=>{const m=text.match(/(\d+)(?:\s*[\u2013-]\s*(\d+))?\s*(?:full\s+)?(seconds?|minutes?)/i);if(!m)return null;const hi=parseInt(m[2]||m[1],10),unit=/min/i.test(m[3])?60:1,secs=hi*unit;if(secs<5||secs>3600)return null;return{secs,label:m[0].replace(/\s+/g," ")};};const timerBeep=()=>{try{const ctx=new (window.AudioContext||window.webkitAudioContext)();const o=ctx.createOscillator(),g=ctx.createGain();o.connect(g);g.connect(ctx.destination);o.frequency.value=880;g.gain.setValueAtTime(.001,ctx.currentTime);g.gain.exponentialRampToValueAtTime(.25,ctx.currentTime+.02);g.gain.exponentialRampToValueAtTime(.001,ctx.currentTime+.9);o.start();o.stop(ctx.currentTime+.95);setTimeout(()=>ctx.close().catch(()=>{}),1200);}catch(e){}};const drawTimerPill=()=>{const old=$(".timer-pill",viewer);if(old)old.remove();if(!timer.total)return;viewer.insertAdjacentHTML("beforeend",`<div class="timer-pill${timer.done?" done":""}" role="timer" aria-live="polite"><span class="timer-time">${timer.done?"Time\u2019s up":fmtT(timer.left)}</span><span class="timer-name">${esc(timer.label)}</span>${timer.done?"":`<button data-timer-pause aria-label="${timer.running?"Pause":"Resume"}">${timer.running?"\u2759\u2759":"\u25B6"}</button>`}<button data-timer-x aria-label="Dismiss timer">\u00d7</button></div>`);const pill=$(".timer-pill",viewer);$("[data-timer-x]",pill).onclick=e=>{e.stopPropagation();clearTimer();drawTimerPill();};const pp=$("[data-timer-pause]",pill);if(pp)pp.onclick=e=>{e.stopPropagation();if(timer.running)stopTimer();else startTicking();drawTimerPill();};};const startTicking=()=>{stopTimer();timer.running=true;timer.iv=setInterval(()=>{timer.left--;if(timer.left<=0){stopTimer();timer.done=true;timer.left=0;if(navigator.vibrate)navigator.vibrate([250,120,250]);timerBeep();}drawTimerPill();},1000);};const startTimer=(secs,label)=>{clearTimer();timer.total=secs;timer.left=secs;timer.label=label;startTicking();drawTimerPill();};const stepsPanelHTML=()=>{let rows="",lastK="";slides.forEach((s,i)=>{const k=s.overview?"OVERVIEW":s.kicker;if(k!==lastK){rows+=`<p class="steps-group">${esc(k)}</p>`;lastK=k;}rows+=`<button class="steps-row${i===index?" current":i<index?" past":""}" data-jump="${i}"><span>${i===0?"\u25A6":i}</span>${esc(s.overview?recipe.title:s.title)}</button>`;});return`<div class="steps-panel"><div class="steps-sheet"><div class="steps-head"><b>All steps</b><button class="steps-x" aria-label="Close">\u00d7</button></div><div class="steps-list">${rows}</div></div></div>`;};const openStepsPanel=()=>{if($(".steps-panel",viewer))return;viewer.insertAdjacentHTML("beforeend",stepsPanelHTML());const panel=$(".steps-panel",viewer);panel.onclick=e=>{if(e.target===panel)panel.remove();};$(".steps-x",panel).onclick=e=>{e.stopPropagation();panel.remove();};$$("[data-jump]",panel).forEach(b=>b.onclick=e=>{e.stopPropagation();index=clamp(parseInt(b.dataset.jump,10),0,slides.length-1);panel.remove();draw();});const cur=$(".steps-row.current",panel);if(cur)cur.scrollIntoView({block:"center"});};const teardown=()=>{clearTimer();releaseWakeLock();viewer.remove();};const close=()=>{if(index>0&&index<slides.length-1){state.recipeProgress[recipe.id]=index;save();}closeLayer(layer);teardown();render();};const draw=()=>{const slide=slides[index],pct=Math.round((index+1)/slides.length*100);viewer.innerHTML=`<div class="story-progress">${slides.map((_,i)=>`<i class="${i<=index?"active":""}"></i>`).join("")}</div><div class="story-meta">${esc(recipe.title)} · ${index+1} / ${slides.length} · ${pct}%</div><button class="story-close" aria-label="Close">×</button><div class="story-slide">${img(slide.image,slide.title,true)}${slide.overview?`<div class="recipe-overview"><p class="eyebrow" style="color:#fff">${esc(slide.kicker)}</p><h2>${esc(recipe.title)}</h2><div class="recipe-profile"><span><b>Flavour</b>${esc(recipe.flavour)}</span><span><b>Texture</b>${esc(recipe.texture)}</span></div><div class="recipe-macros">${recipe.macroLabels?`<span><strong>${recipe.macros.calories}</strong>${recipe.macroLabels.calories}</span><span><strong>${recipe.macros.protein}</strong>${recipe.macroLabels.protein}</span><span><strong>${recipe.macros.fat}</strong>${recipe.macroLabels.fat}</span><span><strong>${recipe.macros.carbs}</strong>${recipe.macroLabels.carbs}</span>`:`<span><strong>${recipe.macros.calories}</strong>kcal</span><span><strong>${recipe.macros.protein} g</strong>protein</span><span><strong>${recipe.macros.fat} g</strong>fat</span><span><strong>${recipe.macros.carbs} g</strong>carbs</span>`}</div><div class="recipe-ingredients"><b>Ingredients</b><p>${recipe.ingredients.map(esc).join(" · ")}</p></div>${saved_pos?`<div style="display:flex;gap:8px;margin-top:12px"><button class="btn btn-primary" data-resume-recipe style="flex:1">Resume step ${saved_pos+1}</button><button class="btn btn-secondary" data-startover-recipe style="flex:1">Start over</button></div>`:`<p class="tap-cue">Tap right to start cooking</p>`}</div>`:`<div class="story-content"><p class="eyebrow" style="color:#fff">${esc(slide.kicker)}</p><h2>${esc(slide.title)}</h2><p>${esc(slide.body)}</p>${(()=>{const p=slide.noTimer?null:parseTimer(slide.title+" "+slide.body);return p?`<button class="timer-chip" data-timer-start="${p.secs}" data-timer-name="${esc(slide.title)}">\u23F1 Start ${fmtT(p.secs)} timer <em>(${esc(p.label)})</em></button>`:"";})()}</div>`}<div class="story-tap"><button aria-label="Previous"></button><button aria-label="Next"></button></div></div><button class="steps-btn" aria-label="All steps">\u2630</button>`;$(".story-close",viewer).onclick=close;$(".steps-btn",viewer).onclick=e=>{e.stopPropagation();openStepsPanel();};const tChip=$("[data-timer-start]",viewer);if(tChip)tChip.onclick=e=>{e.stopPropagation();startTimer(parseInt(tChip.dataset.timerStart,10),tChip.dataset.timerName);};drawTimerPill();const [prev,next]=$$(".story-tap button",viewer);prev.onclick=()=>go(-1);next.onclick=()=>go(1);const rBtn=$("[data-resume-recipe]",viewer),sBtn=$("[data-startover-recipe]",viewer);if(rBtn)rBtn.onclick=e=>{e.stopPropagation();index=clamp(saved_pos,0,slides.length-1);draw();};if(sBtn)sBtn.onclick=e=>{e.stopPropagation();delete state.recipeProgress[recipe.id];save();index=1;draw();};showTapHint(viewer);if(!viewer.dataset.introDone){viewer.dataset.introDone="1";viewer.insertAdjacentHTML("beforeend",tapIntroHTML());runTapIntro(viewer);}if(index>0){state.recipeProgress[recipe.id]=index;save();}[index+1,index+2].forEach(i=>{const s=slides[i];if(s){const image=new Image();image.src=preloadSrc(s.image);}});};const go=direction=>{const now=Date.now();if(now-last<250)return;last=now;if(direction>0)tapHintAdvance(viewer);if(direction>0&&index===slides.length-1){if(opts.side){if(!state.completedSides.includes(recipe.id))state.completedSides.push(recipe.id);delete state.recipeProgress[recipe.id];save();viewer.innerHTML=`<div class="recipe-complete">${img(recipe.hero,recipe.title,true)}<div><p class="eyebrow" style="color:#fff">READY TO SERVE</p><h2>${esc(recipe.doneTitle||"Done — and delicious.")}</h2><p>${esc(recipe.doneBody||recipe.subtitle||"")}</p><button class="btn btn-primary" data-recipe-close>Close</button></div></div>`;$("[data-recipe-close]",viewer).onclick=()=>{closeLayer(layer);teardown();render()};return;}if(opts.custom){delete state.recipeProgress[recipe.id];save();const steakStory=recipe.steak===true;viewer.innerHTML=`<div class="recipe-complete">${img(recipe.hero,recipe.title,true)}<div><p class="eyebrow" style="color:#fff">${steakStory?"PROTOCOL COMPLETE":"BUILD COMPLETE"}</p><h2>${steakStory?"You cooked your own protocol.":"You cooked your own build."}</h2><p>${steakStory?`${esc(recipe.title)} — pulled at ${recipe.macros.calories}, landed in the ${esc(recipe.ingredients[3]||"target")} window. Save the protocol to your Steak Lab to refine the timings next cook.`:`${esc(recipe.title)} — ${recipe.macros.calories} kcal, ${recipe.macros.protein} g protein, cooked to your exact spec. Save it to your Lab to keep this recipe, or head back to the Builder and refine it.`}</p><button class="btn btn-primary" data-build-save>${steakStory?"Save to Steak Lab":"Save to Burger Lab"}</button><button class="btn btn-secondary" data-recipe-close>Close</button></div></div>`;$("[data-build-save]",viewer).onclick=()=>{if(recipe.steak===true)saveProtocol();else saveBuild();closeLayer(layer);teardown();route("builder")};$("[data-recipe-close]",viewer).onclick=()=>{closeLayer(layer);teardown();render()};return;}completeRecipe(recipe);viewer.innerHTML=`<div class="recipe-complete">${img(recipe.hero,recipe.title,true)}<div><p class="eyebrow" style="color:#fff">RECIPE COMPLETE</p><h2>You built ${esc(recipe.title)}.</h2><p>The recipe has been added to your Lab and loaded into the Builder for adaptation.</p><button class="btn btn-primary" data-recipe-finish>Open Builder</button><button class="btn btn-secondary" data-recipe-close>Close</button></div></div>`;$("[data-recipe-finish]",viewer).onclick=()=>{closeLayer(layer);teardown();route("builder")};$("[data-recipe-close]",viewer).onclick=()=>{closeLayer(layer);teardown();render()};return;}index=clamp(index+direction,0,slides.length-1);draw();};viewer.addEventListener("touchstart",e=>{if(e.touches.length===1){tracking=true;sx=e.touches[0].clientX;sy=e.touches[0].clientY}},{passive:true});viewer.addEventListener("touchend",e=>{if(!tracking)return;tracking=false;const dx=e.changedTouches[0].clientX-sx,dy=e.changedTouches[0].clientY-sy;if(Math.abs(dx)>48&&Math.abs(dx)>Math.abs(dy)*1.4)go(dx<0?1:-1);else if(dy>90&&Math.abs(dy)>Math.abs(dx)*1.6)close()},{passive:true});document.body.appendChild(viewer);draw();}
function home(){const r=metrics(),mastery=unifiedProgress();syncChallenges(r);return `<div class="home-layout"><section class="hero card">${img(assets.heroEditorial,"Premium cheeseburger",true)}<div class="hero-copy"><span class="pill">YOUR GUIDED JOURNEY</span><h2>${state.completed.length<courses.length?"Continue your lesson.":state.completedRecipes.length<1?"Cook your first burger.":state.savedBuilds.length<1?"Design your own burger.":"Take on a challenge."}</h2><p>${state.completed.length<courses.length?"Pick up Burger Essentials right where you stopped.":state.completedRecipes.length<1?"Open a Signature Recipe and follow it step by step.":state.savedBuilds.length<1?"Adapt any recipe in the Builder and save it to your Lab.":"Push your current build to complete the next guided challenge."}</p><button class="btn btn-secondary" data-next-step>${state.completed.length<courses.length?"Continue learning":state.completedRecipes.length<1?"Open recipes":state.savedBuilds.length<1?"Open Builder":"View challenges"}</button></div></section><div class="side-stack"><section class="section"><div class="section-head"><div><h2>Overall mastery</h2><p>Learn · Cook · Build · Challenge</p></div></div><article class="card progress-row tappable" data-go="profile" role="button" tabindex="0" aria-label="View your full progress breakdown"><div class="progress-label"><span>Your Burger Journey</span><strong>${mastery}%</strong></div><div class="progress"><i style="width:${mastery}%"></i></div><p class="tap-more">View full breakdown ›</p></article></section><section class="section"><div class="section-head"><div><h2>Your burger in the Builder</h2><p>The build you’re working on · estimated cooked nutrition</p></div></div><article class="card media-card">${img(assets.heroTopdown,"Current burger",false,"card")}<div class="media-copy"><h3>${esc(state.builder.name)}</h3><p>${r.cooked.protein} g protein · ${r.cooked.calories} kcal</p><button class="link-btn" data-go="builder">Edit build</button></div></article></section></div></div>${fullCollectionSection()}${sidesSection()}<section class="section"><div class="section-head"><div><h2>Guided challenges</h2><p>Tap a challenge to see which of your builds achieved it</p></div></div>${challengeCards(r)}</section><section class="section">${installCard()}</section>`;}
// RC2-M06: chapter completion is derived from genuinely viewed slides, never bulk-granted.
const chapterSlideIdx=id=>lessonSequence.reduce((a,s,i)=>{if(s.sectionId===id)a.push(i);return a;},[]);
const chapterPct=id=>{const idx=chapterSlideIdx(id);const seen=idx.filter(i=>state.viewedLessons.includes(i)).length;return idx.length?Math.round(seen/idx.length*100):0;};
const chapterDone=id=>chapterPct(id)===100;
function recomputeCompleted(){state.completed=courses.filter(c=>chapterDone(c.id)).map(c=>c.id);save();}
function markViewed(i){if(!state.viewedLessons.includes(i)){state.viewedLessons.push(i);recomputeCompleted();}}
function learn(){return `<section class="section"><div class="section-head"><div><h2>Build from the inside out</h2><p>Tap any chapter or resume the journey</p></div></div><button class="btn btn-primary full-btn" data-resume>Resume · ${state.storyIndex+1} / ${lessonSequence.length}</button><div class="course-list builder-gap">${courses.map((c,i)=>{const pct=chapterPct(c.id),done=chapterDone(c.id);return `<article class="card course ${done?"done":""}" data-story="${c.id}">${img(c.image,c.title,false,"card")}<div class="course-body"><strong>${c.title}</strong><p>${c.subtitle}</p><div class="progress"><i style="width:${pct}%"></i></div></div><span class="course-num">${done?"✓":i+1}</span></article>`;}).join("")}</div></section>`;}
const field=(label,key,list)=>`<label class="builder-field"><span>${label}<button type="button" class="info-dot" data-detail="${key}">i</button></span><select data-builder="${key}">${list.map(x=>`<option value="${x.id}" ${state.builder[key]===x.id?"selected":""}>${esc(x.label)}</option>`).join("")}</select></label>`,score=(l,v)=>`<div class="score-row"><span>${l}</span><div class="score-track"><i style="width:${v}%"></i></div><strong>${v}</strong></div>`;
function comparison(r){if(!state.savedBuilds.length)return `<article class="card comparison-card"><p class="eyebrow">COMPARE BUILDS</p><h3>Save a build to unlock comparison.</h3><p>Your current burger can then be compared against a previous experiment.</p></article>`;const chosen=state.savedBuilds.find(x=>x.id===state.compareId)||state.savedBuilds.at(-1),other=metrics(chosen.build),rows=[["Cooked kcal",r.cooked.calories,other.cooked.calories],["Protein",r.cooked.protein,other.cooked.protein],["Fat",r.cooked.fat,other.cooked.fat],["Juiciness",r.scores.juiciness,other.scores.juiciness],["Crust",r.scores.crust,other.scores.crust],["Structure",r.scores.structure,other.scores.structure]];return `<article class="card comparison-card"><div class="builder-title-row"><div><p class="eyebrow">COMPARE BUILDS</p><h3>Current vs saved</h3></div><select data-compare>${state.savedBuilds.slice().reverse().map(x=>`<option value="${x.id}" ${x.id===chosen.id?"selected":""}>${esc(x.name)}</option>`).join("")}</select></div><div class="compare-grid"><b>Metric</b><b>Current</b><b>${esc(chosen.name)}</b>${rows.map(x=>`<span>${x[0]}</span><strong>${x[1]}</strong><strong>${x[2]}</strong>`).join("")}</div></article>`;}
function builder(){const r=metrics(),rr=recommendations(r);syncChallenges(r);return `<section class="builder-preview card">${img(assets.heroHighProtein,"Burger preview",true)}<div class="builder-preview-overlay"><span class="pill">LIVE BUILD</span><h2>${esc(state.builder.name)}</h2><p>${r.m.label} · ${state.builder.weight} g raw → ${r.cooked.pattyWeight} g cooked</p></div></section><section class="section builder-shell"><article class="card builder-panel"><div class="builder-title-row"><div><p class="eyebrow">BURGER BUILDER</p><h2>Design the patty first</h2></div><button class="icon-btn" data-reset aria-label="Reset">↺</button></div><label class="builder-field"><span>Build name</span><input data-builder="name" value="${esc(state.builder.name)}" maxlength="36"></label>${field("Meat blend","meat",builderCatalogue.meats)}<label class="builder-field range-field"><span><b>Patty weight</b><output data-output="weight">${state.builder.weight} g</output></span><input type="range" min="90" max="240" step="10" value="${state.builder.weight}" data-builder="weight"></label><label class="builder-field range-field"><span><b>Thickness</b><output data-output="thickness">${thicknessLabel(state.builder.thickness)}</output></span><input type="range" min="6" max="30" value="${state.builder.thickness}" data-builder="thickness"></label><div class="aromatics-head"><p class="eyebrow">AROMATICS &amp; MIX-INS</p><p class="aromatics-sub">Flavour the patty itself — this is where mixing becomes taste</p></div>${field("Onion in the mix","onion",builderCatalogue.onions)}${field("Garlic","garlic",builderCatalogue.garlics)}${field("Seasoning profile","seasoning",builderCatalogue.seasonings)}<div class="aromatics-head"><p class="eyebrow">AROUND THE PATTY</p></div>${field("Cheese","cheese",builderCatalogue.cheeses)}${field("Bun","bun",builderCatalogue.buns)}${field("Sauce","sauce",builderCatalogue.sauces)}</article><article class="card nutrition-card"><div class="builder-title-row"><div><p class="eyebrow">ESTIMATED COOKED NUTRITION</p><h2><span data-metric="calories">${r.cooked.calories}</span> kcal</h2></div><div class="score-badge"><strong data-metric="overall">${r.overall}</strong><span>score</span></div></div><div class="macro-grid"><div><strong data-metric="protein">${r.cooked.protein} g</strong><span>protein</span></div><div><strong data-metric="fat">${r.cooked.fat} g</strong><span>fat retained</span></div><div><strong data-metric="carbs">${r.cooked.carbs} g</strong><span>carbs</span></div><div><strong data-metric="density">${r.density} g</strong><span>protein / 100 kcal</span></div></div><details class="raw-details"><summary>See raw-input estimate</summary><p>${r.raw.calories} kcal · ${r.raw.protein} g protein · ${r.raw.fat} g fat · ${r.raw.carbs} g carbs</p><p>Estimated cooked patty yield: ${r.cooked.pattyWeight} g from ${state.builder.weight} g raw.</p></details><p class="estimate-note">Estimates use generic ingredient data and model cooking loss. Brands, fat drainage and doneness vary.</p></article><article class="card insight-card" data-live-insight><p class="eyebrow">WHY IT CHANGED</p><h3>Change any ingredient</h3><div class="insight-tiers"><p><b>Flavour</b>What it does to taste — explained here the moment you change something.</p><p><b>Technique</b>What it changes at the pan.</p><p><b>Nutrition</b>What it costs or saves.</p></div></article><article class="card score-card"><p class="eyebrow">EATING EXPERIENCE</p>${score("Juiciness",r.scores.juiciness)}${score("Tenderness",r.scores.tenderness)}${score("Beef flavour",r.scores.beefiness)}${score("Richness",r.scores.richness)}${score("Crust potential",r.scores.crust)}${score("Structure",r.scores.structure)}</article><article class="card coach-card"><p class="eyebrow">BURGER COACH</p><div data-recs>${rr.map(x=>`<div class="coach-tip"><strong>${x[0]}</strong><p>${x[1]}</p></div>`).join("")}</div><div class="optimizer-row"><button class="btn btn-secondary" data-opt="protein">Higher protein</button><button class="btn btn-secondary" data-opt="calories">Lower calories</button><button class="btn btn-secondary" data-opt="moisture">More moisture</button></div></article><article class="card validation-card"><p class="eyebrow">LIVE VALIDATION</p>${validation(r).map(x=>`<div class="validation-item"><strong>${x[0]}</strong><p>${x[1]}</p></div>`).join("")}</article>${challengeCards(r)}${comparison(r)}<button class="btn btn-primary full-btn" data-cook-build>Cook this build</button><button class="btn btn-secondary full-btn" data-save>Save to Burger Lab</button></section><section class="section adaptation-panel"><div class="section-head"><div><h2>Adapt a Signature Recipe</h2><p>Start from a proven build, then optimise it</p></div></div><div class="adapt-grid">${recipes.map(x=>`<article class="card adapt-card"><strong>${esc(x.title)}</strong><div><button class="link-btn" data-adapt="protein" data-recipe-id="${x.id}">Higher protein</button><button class="link-btn" data-adapt="calories" data-recipe-id="${x.id}">Lower calorie</button><button class="link-btn" data-adapt="moisture" data-recipe-id="${x.id}">Juicier</button><button class="link-btn" data-adapt="crust" data-recipe-id="${x.id}">Better crust</button></div></article>`).join("")}</div></section>${recipeSection(6)}${saved()}`;}
// RC2-m01: learner-facing thickness shows curriculum-equivalent units alongside millimetres.
const thicknessLabel=mm=>`${mm} mm (${(mm/25.4).toFixed(2).replace(/0$/,"")}″ · ${(mm/10).toFixed(1)} cm)`;
// RC2-M07: saved builds support open, rename, favourite and confirmed delete.
function saved(){return state.savedBuilds.length?`<section class="section"><div class="section-head"><div><h2>Saved builds</h2><p>Open, rename, favourite or delete</p></div></div><div class="saved-builds">${state.savedBuilds.slice().reverse().map(b=>`<article class="card saved-build"><button class="saved-open" data-load="${b.id}"><strong>${esc(b.name)}</strong><small>${b.result.protein} g protein · ${b.result.calories} kcal</small></button><span class="saved-actions"><button class="mini-btn" data-rename="${b.id}" aria-label="Rename build">✎</button><button class="mini-btn" data-favorite="${b.id}" aria-label="Favourite build">${state.favoriteBuildId===b.id?"★":"☆"}</button><button class="mini-btn" data-delete="${b.id}" aria-label="Delete build">🗑</button></span></article>`).join("")}</div></section>`:"";}
function lab(){const cooked=state.completedRecipes.length?`<section class="section"><div class="section-head"><div><h2>Recipes cooked</h2><p>${state.completedRecipes.length} completed</p></div></div><div class="completed-recipes">${state.completedRecipes.slice().reverse().map(item=>`<article class="card completed-recipe"><span><strong>${esc(item.title)}</strong><small>${new Date(item.completedAt).toLocaleDateString()} · ${item.macros.protein} g protein · ${item.macros.calories} kcal</small></span><button class="link-btn" data-recipe="${item.id}">Cook again</button></article>`).join("")}</div></section>`:"";return cooked+(state.savedBuilds.length?`<section class="section"><div class="section-head"><div><h2>Saved Burger Genomes</h2><p>${state.savedBuilds.length} experiments</p></div></div><div class="saved-builds">${state.savedBuilds.slice().reverse().map(b=>`<article class="card lab-build"><div><p class="eyebrow">${new Date(b.savedAt).toLocaleDateString()}</p><h3>${esc(b.name)}</h3><p>${esc(b.result.meat)} · ${b.build.weight} g raw · ${esc(b.result.cheese)}</p></div><div class="lab-macros"><strong>${b.result.protein} g</strong><span>protein</span><strong>${b.result.calories}</strong><span>kcal</span></div><button class="link-btn" data-load="${b.id}">Edit build</button></article>`).join("")}</div></section>`:`<section class="card empty"><div class="orb">🧪</div><h2>Your experiments will live here.</h2><p>Build a burger, save it and return here to compare your decisions.</p><button class="btn btn-primary" data-go="builder">Build your first burger</button></section>`);}
function profile(){const r=metrics(),mastery=unifiedProgress(),fav=state.savedBuilds.find(x=>x.id===state.favoriteBuildId)||state.savedBuilds[0];const best=state.savedBuilds.reduce((a,b)=>!a||b.result.overall>a.result.overall?b:a,null);return `<section class="section"><article class="card dashboard-hero"><p class="eyebrow">BURGER MASTERY</p><h2>${mastery}% mastered</h2><div class="progress"><i style="width:${mastery}%"></i></div><p>Your progress combines learning, cooking, experimentation and challenges.</p></article></section><section class="section"><div class="dashboard-grid"><article class="card metric"><strong>${state.completed.length}/${courses.length}</strong><span>chapters complete</span></article><article class="card metric"><strong>${state.completedRecipes.length}</strong><span>recipes cooked</span></article><article class="card metric"><strong>${state.completedSides.length}</strong><span>sides &amp; condiments</span></article><article class="card metric"><strong>${state.savedBuilds.length}</strong><span>experiments</span></article><article class="card metric"><strong>${state.completedChallenges.length}/${challenges.length}</strong><span>challenges</span></article></div></section>${fav?`<section class="section"><div class="section-head"><div><h2>Favourite burger</h2><p>Your selected build</p></div></div><article class="card panel"><h3>${esc(fav.name)}</h3><p>${fav.result.protein} g protein · ${fav.result.calories} kcal · score ${fav.result.overall}</p><button class="link-btn" data-load="${fav.id}">Open build</button></article></section>`:""}${best?`<section class="section"><div class="section-head"><div><h2>Personal best</h2><p>Highest saved overall score</p></div></div><article class="card panel"><h3>${esc(best.name)}</h3><p>Overall score ${best.result.overall} · ${best.result.protein} g protein · ${best.result.calories} kcal</p></article></section>`:""}<section class="section"><div class="section-head"><div><h2>Challenges</h2><p>Progress updates live from Builder</p></div></div>${challengeCards(r)}</section><section class="section">${installCard()}</section>`;}
// v2.0.0: render dispatches on the active discipline. Burger views are untouched; steak views arrive via steak-*.js data modules.
function render(){syncChip();const views=state.discipline==="steak"?{home:steakHome,builder:steakBuilder,learn:steakLearn,flavours:steakFlavours,lab:steakLab,profile:steakProfile}:{home,builder,learn,flavours,lab,profile};app.innerHTML=(views[state.route]||views.home)();}
// v2.0.0: steak views. The Designer builds a cooking protocol; the metrics engine computes pull temp, cook and rest times with honest warnings.
function steakHome(){const m=steakMetrics(state.steak.protocol);return `<div class="home-layout"><section class="hero card">${img(assets.heroSteak,"Seared ribeye steak",true)}<div class="hero-copy"><span class="pill">STEAK ROUTE</span><h2>Design tonight's steak.</h2><p>Pick a cut, a method and a doneness — the Designer writes your exact protocol: pull temperature, timings and rest.</p><button class="btn btn-secondary" data-go="builder">Open the Steak Designer</button></div></section><div class="side-stack"><section class="section"><div class="section-head"><div><h2>Your protocol</h2><p>The steak you’re designing right now</p></div></div><article class="card media-card">${img(assets.heroSteak,"Current steak protocol",false,"card")}<div class="media-copy"><h3>${esc(state.steak.protocol.name)}</h3><p>${m.cut.label} · ${m.th.cm} cm · ${m.dn.label} · pull ${m.me.id==="sousvide"?`bath ${m.target}`:m.pull}°C</p><button class="link-btn" data-go="builder">Edit protocol</button></div></article></section><section class="section"><div class="section-head"><div><h2>Coming in the next release</h2><p>The staged v2.x roadmap</p></div></div><article class="card panel"><h3>Steak Essentials · Doneness Decoded · Signature Steaks</h3><p>The full lesson curriculum, the doneness taste guide and signature cook-alongs (butter-basted ribeye, reverse-seared tomahawk and more) arrive next. The Designer below is fully functional today.</p></article></section></div></div>${steakSavedSection()}<section class="section">${installCard()}</section>`;}
function steakSavedSection(){return state.steak.savedProtocols.length?`<section class="section"><div class="section-head"><div><h2>Saved protocols</h2><p>${state.steak.savedProtocols.length} in your Steak Lab</p></div></div><div class="saved-builds">${state.steak.savedProtocols.slice().reverse().map(b=>`<article class="card saved-build"><button class="saved-open" data-load-protocol="${b.id}"><strong>${esc(b.name)}</strong><small>${esc(b.summary)}</small></button><span class="saved-actions"><button class="mini-btn" data-delete-protocol="${b.id}" aria-label="Delete protocol">🗑</button></span></article>`).join("")}</div></section>`:"";}
const sfield=(label,key,list)=>`<label class="builder-field"><span>${label}</span><select data-steak="${key}">${list.map(o=>`<option value="${o.id}" ${state.steak.protocol[key]===o.id?"selected":""}>${esc(o.label)}</option>`).join("")}</select></label>`;
const sscore=(label,v)=>`<div class="score-row"><span>${label}</span><div class="score-track"><i style="width:${v}%"></i></div><strong>${v}</strong></div>`;
function steakInsight(m){return `<p><b>Cut</b>${esc(m.cut.flavour)} ${esc(m.cut.donenessNote)}</p><p><b>Method</b>${esc(m.me.profile)} ${esc(m.me.carryover)}</p><p><b>Prep</b>${esc(m.pr.note)}${m.gr.heatNote?` ${esc(m.gr.heatNote)}`:""}</p>`;}
function steakBuilder(){const m=steakMetrics(state.steak.protocol);return `<section class="builder-preview card">${img(assets.heroSteak,"Steak protocol preview",true)}<div class="builder-preview-overlay"><h2>${esc(state.steak.protocol.name)}</h2><p>${m.cut.label} · ${m.th.cm} cm · ${m.gr.label} · ${m.dn.label} by ${m.me.label}</p></div></section><section class="section builder-shell"><article class="card builder-panel"><div class="builder-title-row"><div><p class="eyebrow">STEAK DESIGNER</p><h2>Design the protocol</h2></div><button class="icon-btn" data-steak-reset aria-label="Reset">↺</button></div><label class="builder-field"><span>Protocol name</span><input data-steak="name" value="${esc(state.steak.protocol.name)}" maxlength="36"></label>${sfield("Cut","cut",steakCatalogue.cuts)}${sfield("Thickness","thickness",steakCatalogue.thicknesses)}${sfield("Grade","grade",steakCatalogue.grades)}${sfield("Preparation","preparation",steakCatalogue.preparations)}${sfield("Method","method",steakCatalogue.methods)}${sfield("Target doneness","doneness",steakCatalogue.donenesses)}${sfield("Finish","finish",steakCatalogue.finishes)}</article><article class="card nutrition-card"><div class="builder-title-row"><div><p class="eyebrow">${m.me.id==="sousvide"?"BATH TEMPERATURE":"PULL TEMPERATURE"}</p><h2><span data-smetric="pull">${m.me.id==="sousvide"?m.target:m.pull}</span> °C</h2></div><div class="score-badge"><strong data-smetric="match">${m.match}</strong><span>match</span></div></div><div class="macro-grid"><div><strong data-smetric="target">${m.dn.band}</strong><span>after-rest target</span></div><div><strong data-smetric="cook">${m.cookMin} min</strong><span>cook time</span></div><div><strong data-smetric="rest">${m.restMin?`${m.restMin} min`:"serve now"}</strong><span>rest</span></div><div><strong data-smetric="total">${m.totalMin} min</strong><span>total${m.prepMin>=60?` + ${m.prepMin>=1440?"24 h":"1 h"} brine`:""}</span></div></div><p class="estimate-note" data-smetric="pullnote">${esc(m.pullNote)} ${esc(m.cookNote)}</p></article><article class="card insight-card" data-steak-insight><p class="eyebrow">WHY THIS PROTOCOL</p><h3>${esc(m.cut.label)}, ${m.dn.label.toLowerCase()}, by ${m.me.label.toLowerCase()}</h3><div class="insight-tiers">${steakInsight(m)}</div></article><article class="card score-card"><p class="eyebrow">EATING EXPERIENCE</p>${sscore("Crust",m.scores.crust)}${sscore("Juiciness",m.scores.juiciness)}${sscore("Tenderness",m.scores.tenderness)}${sscore("Fat rendering",m.scores.render)}${sscore("Effort",m.scores.effort)}</article><article class="card validation-card" data-steak-warnings><p class="eyebrow">LIVE VALIDATION</p>${steakWarnings(m)}</article><button class="btn btn-primary full-btn" data-cook-steak>Cook this protocol</button><button class="btn btn-secondary full-btn" data-save-protocol>Save to Steak Lab</button></section>${steakSavedSection()}`;}
function steakWarnings(m){return m.warnings.length?m.warnings.map(w=>`<div class="validation-item"><strong>${esc(w[0])}</strong><p>${esc(w[1])}</p></div>`).join(""):`<div class="validation-item"><strong>Protocol sound</strong><p>Cut, thickness, method and doneness all agree. ${esc(m.cut.slicing)}</p></div>`;}
function updateSteak(){const m=steakMetrics(state.steak.protocol);const set=(k,v)=>{const e=$(`[data-smetric="${k}"]`);if(e)e.textContent=v};set("pull",m.me.id==="sousvide"?m.target:m.pull);set("match",m.match);set("target",m.dn.band);set("cook",`${m.cookMin} min`);set("rest",m.restMin?`${m.restMin} min`:"serve now");set("total",`${m.totalMin} min`);const pn=$('[data-smetric="pullnote"]');if(pn)pn.textContent=`${m.pullNote} ${m.cookNote}`;const ins=$("[data-steak-insight]");if(ins)ins.innerHTML=`<p class="eyebrow">WHY THIS PROTOCOL</p><h3>${esc(m.cut.label)}, ${m.dn.label.toLowerCase()}, by ${m.me.label.toLowerCase()}</h3><div class="insight-tiers">${steakInsight(m)}</div>`;const wc=$("[data-steak-warnings]");if(wc)wc.innerHTML=`<p class="eyebrow">LIVE VALIDATION</p>${steakWarnings(m)}`;const vals=Object.values(m.scores);$$(".score-card .score-row").forEach((row,i)=>{if(vals[i]!==undefined){$("i",row).style.width=`${vals[i]}%`;$("strong",row).textContent=vals[i];}});const h=$(".builder-preview-overlay h2"),p=$(".builder-preview-overlay p");if(h)h.textContent=state.steak.protocol.name;if(p)p.textContent=`${m.cut.label} · ${m.th.cm} cm · ${m.gr.label} · ${m.dn.label} by ${m.me.label}`;}
function saveProtocol(){const m=steakMetrics(state.steak.protocol);state.steak.savedProtocols.push({id:`protocol-${Date.now()}`,name:state.steak.protocol.name||"Untitled Steak",savedAt:new Date().toISOString(),protocol:{...state.steak.protocol},summary:`${m.cut.label} · ${m.dn.label} · pull ${m.me.id==="sousvide"?`bath ${m.target}`:m.pull}°C · ${m.totalMin} min`});save();render();}
function steakLab(){return state.steak.savedProtocols.length?steakSavedSection():`<section class="card empty"><div class="orb">🥩</div><h2>Your protocols will live here.</h2><p>Design a steak, save the protocol, and refine your pull temperatures cook after cook.</p><button class="btn btn-primary" data-go="builder">Design your first steak</button></section>`;}
function steakProfile(){const saved_n=state.steak.savedProtocols.length;return `<section class="section"><article class="card dashboard-hero"><p class="eyebrow">MEAT MASTERY · STEAK</p><h2>The steak journey begins</h2><div class="progress"><i style="width:${Math.min(saved_n*20,100)}%"></i></div><p>Steak mastery tracking arrives with the full curriculum. For now, every saved protocol builds your foundation.</p></article></section><section class="section"><div class="dashboard-grid"><article class="card metric"><strong>${saved_n}</strong><span>protocols saved</span></article><article class="card metric"><strong>7</strong><span>cuts to master</span></article><article class="card metric"><strong>6</strong><span>methods available</span></article><article class="card metric"><strong>5</strong><span>doneness targets</span></article></div></section><section class="section">${installCard()}</section>`;}
function steakComingSoon(what){return `<section class="card empty"><div class="orb">🔥</div><h2>${what} is being plated.</h2><p>This part of the steak curriculum arrives in the next release. The Steak Designer is fully functional today — design a protocol and cook along.</p><button class="btn btn-primary" data-go="builder">Open the Steak Designer</button></section>`;}
function steakLearn(){return steakComingSoon("Steak Essentials");}
function steakFlavours(){return steakComingSoon("The Science of Beef");}
function openCookSteak(){const story=generateSteakStory(state.steak.protocol,steakMetrics(state.steak.protocol));delete state.recipeProgress[story.id];save();openRecipeStory(story,{custom:true});}
// v2.0.0: full-screen discipline chooser — shown on first launch (discipline null) and reopenable from the header chip.
function syncChip(){const chip=document.querySelector("#disciplineChip");if(chip)chip.textContent=state.discipline==="steak"?"MEAT MASTERY · STEAK":state.discipline==="burger"?"MEAT MASTERY · BURGER":"MEAT MASTERY";}
function openChooser(dismissible=true){if(document.querySelector(".chooser-overlay"))return;const el=document.createElement("div");el.className="chooser-overlay";el.innerHTML=`<div class="chooser-inner"><p class="eyebrow">MEAT MASTERY</p><h2>What are we mastering today?</h2><p class="chooser-sub">Two crafts, one kitchen. Your progress is saved separately in each.</p><div class="chooser-cards"><button class="chooser-card" data-discipline="burger">${img(assets.heroChooserBurger,"The burger discipline",true,"card")}<span class="chooser-label"><strong>Burger</strong><small>Blend, build &amp; stack</small></span></button><button class="chooser-card" data-discipline="steak">${img(assets.heroSteak,"The steak discipline",true,"card")}<span class="chooser-label"><strong>Steak</strong><small>Source, sear &amp; rest</small></span></button></div>${dismissible?'<button class="link-btn chooser-close">Stay where I am</button>':""}</div>`;document.body.appendChild(el);requestAnimationFrame(()=>el.classList.add("open"));const close=()=>{el.classList.remove("open");setTimeout(()=>el.remove(),300);};el.addEventListener("click",e=>{const c=e.target.closest("[data-discipline]");if(c){const changed=state.discipline!==c.dataset.discipline;state.discipline=c.dataset.discipline;save();close();if(changed)route("home");else render();}if(e.target.closest(".chooser-close")&&dismissible)close();});}
document.addEventListener("click",e=>{if(e.target.closest("#disciplineChip")||e.target.closest("[data-open-chooser]"))openChooser(state.discipline!==null);});
function flavours(){const groups=[...new Set(flavourTopics.map(t=>t.category))];return groups.map(cat=>`<section class="section"><div class="section-head"><div><h2>${esc(cat)}</h2><p>${cat==="Meat Taste Guides"?"How each meat tastes and what pairs with it":"When, why and how much to add"}</p></div></div><div class="recipe-grid">${flavourTopics.filter(t=>t.category===cat).map(t=>`<button class="recipe-card card" data-flavour="${t.id}">${img(t.hero,t.title)}<span class="recipe-card-copy"><small>${esc(t.flavour)}</small><strong>${esc(t.title)}</strong><em>${t.slides.length} slides · tap to explore</em></span></button>`).join("")}</div></section>`).join("");}
function openFlavour(id){const topic=flavourTopics.find(t=>t.id===id);if(!topic)return;const slides=topic.slides;let index=0,last=0,sx=0,sy=0,tracking=false;const viewer=document.createElement("section");viewer.className="story recipe-story";const layer=pushLayer(()=>{teardown();render();});acquireWakeLock();const teardown=()=>{releaseWakeLock();viewer.remove();};const close=()=>{closeLayer(layer);teardown();render()};const draw=()=>{const slide=slides[index],pct=Math.round((index+1)/slides.length*100);viewer.innerHTML=`<div class="story-progress">${slides.map((_,i)=>`<i class="${i<=index?"active":""}"></i>`).join("")}</div><div class="story-meta">${esc(topic.title)} · ${index+1} / ${slides.length} · ${pct}%</div><button class="story-close" aria-label="Close">×</button><div class="story-slide">${img(slide.image,slide.title,true)}<div class="story-content"><p class="eyebrow" style="color:#fff">${esc(slide.kicker)}</p><h2>${esc(slide.title)}</h2><p>${esc(slide.body)}</p></div><div class="story-tap"><button aria-label="Previous"></button><button aria-label="Next"></button></div></div>`;$(".story-close",viewer).onclick=close;const [prev,next]=$$(".story-tap button",viewer);prev.onclick=()=>go(-1);next.onclick=()=>go(1);showTapHint(viewer);if(!viewer.dataset.introDone){viewer.dataset.introDone="1";viewer.insertAdjacentHTML("beforeend",tapIntroHTML());runTapIntro(viewer);}[index+1,index+2].forEach(i=>{const s=slides[i];if(s){const image=new Image();image.src=preloadSrc(s.image);}});};const go=direction=>{const now=Date.now();if(now-last<250)return;last=now;if(direction>0)tapHintAdvance(viewer);if(direction>0&&index===slides.length-1){close();return;}index=clamp(index+direction,0,slides.length-1);draw();};viewer.addEventListener("touchstart",e=>{if(e.touches.length===1){tracking=true;sx=e.touches[0].clientX;sy=e.touches[0].clientY}},{passive:true});viewer.addEventListener("touchend",e=>{if(!tracking)return;tracking=false;const dx=e.changedTouches[0].clientX-sx,dy=e.changedTouches[0].clientY-sy;if(Math.abs(dx)>48&&Math.abs(dx)>Math.abs(dy)*1.4)go(dx<0?1:-1);else if(dy>90&&Math.abs(dy)>Math.abs(dx)*1.6)close()},{passive:true});document.body.appendChild(viewer);draw();}
function updateInsight(info){const el=$("[data-live-insight]");if(el)el.innerHTML=`<p class="eyebrow">WHY IT CHANGED</p><h3>${esc(info.title)}</h3><div class="insight-tiers"><p><b>Flavour</b>${esc(info.flavour)}</p><p><b>Technique</b>${esc(info.technique)}</p><p><b>Nutrition</b>${esc(info.nutrition)}</p></div>`;}
function update(){const r=metrics(),set=(k,v)=>{const e=$(`[data-metric="${k}"]`);if(e)e.textContent=v};set("calories",r.cooked.calories);set("protein",`${r.cooked.protein} g`);set("fat",`${r.cooked.fat} g`);set("carbs",`${r.cooked.carbs} g`);set("density",`${r.density} g`);set("overall",r.overall);Object.values(r.scores).forEach((v,i)=>{const row=$$(".score-row")[i];if(row){$("i",row).style.width=`${v}%`;$('strong',row).textContent=v}});const rec=$("[data-recs]");if(rec)rec.innerHTML=recommendations(r).map(x=>`<div class="coach-tip"><strong>${x[0]}</strong><p>${x[1]}</p></div>`).join("");const w=$('[data-output="weight"]'),t=$('[data-output="thickness"]');if(w)w.textContent=`${state.builder.weight} g`;if(t)t.textContent=thicknessLabel(state.builder.thickness);const h=$(".builder-preview-overlay h2"),p=$(".builder-preview-overlay p");if(h)h.textContent=state.builder.name;if(p)p.textContent=`${r.m.label} · ${state.builder.weight} g raw → ${r.cooked.pattyWeight} g cooked`;const v=$(".validation-card");if(v)v.innerHTML=`<p class="eyebrow">LIVE VALIDATION</p>${validation(r).map(x=>`<div class="validation-item"><strong>${x[0]}</strong><p>${x[1]}</p></div>`).join("")}`;syncChallenges(r);const grid=$(".challenge-grid");if(grid)grid.outerHTML=challengeCards(r);}
function ingredient(key){if(key==="meat")return byId(builderCatalogue.meats,state.builder.meat);if(key==="cheese")return byId(builderCatalogue.cheeses,state.builder.cheese);if(key==="bun")return byId(builderCatalogue.buns,state.builder.bun);if(key==="onion")return aromatic("onions",state.builder.onion);if(key==="garlic")return aromatic("garlics",state.builder.garlic);if(key==="seasoning")return aromatic("seasonings",state.builder.seasoning);return byId(builderCatalogue.sauces,state.builder.sauce);}
function detail(key){const x=ingredient(key),modal=document.createElement("div");modal.className="modal-backdrop";const layer=pushLayer(()=>{modal.classList.add("closing");setTimeout(()=>modal.remove(),220);});modal.innerHTML=`<section class="detail-sheet"><button class="sheet-close">×</button><p class="eyebrow">INGREDIENT INTELLIGENCE</p><h2>${esc(x.label)}</h2><dl><dt>Flavour</dt><dd>${esc(x.flavour)}</dd><dt>Texture</dt><dd>${esc(x.texture)}</dd><dt>Best use</dt><dd>${esc(x.bestUse)}</dd><dt>Common mistake</dt><dd>${esc(x.mistake)}</dd><dt>Cooking approach</dt><dd>${esc(x.cooking)}</dd><dt>Health trade-off</dt><dd>${esc(x.health)}</dd></dl></section>`;const dismiss=()=>{modal.classList.add("closing");setTimeout(()=>modal.remove(),220);};modal.onclick=e=>{if(e.target===modal||e.target.closest(".sheet-close")){closeLayer(layer);dismiss()}};document.body.appendChild(modal);}
function optimize(t){if(t==="protein")Object.assign(state.builder,{meat:"beef90",cheese:"lightcheddar",bun:"thin",sauce:"yoghurt"});if(t==="calories")Object.assign(state.builder,{meat:"beef90",weight:Math.min(state.builder.weight,140),cheese:"none",bun:"lettuce",sauce:"mustard"});if(t==="moisture")Object.assign(state.builder,{meat:state.builder.meat==="beef90"?"beef85":state.builder.meat,sauce:"yoghurt",thickness:Math.max(state.builder.thickness,16)});save();render();}
function saveBuild(){const r=metrics(),item={id:`build-${Date.now()}`,name:state.builder.name||"Untitled Burger",savedAt:new Date().toISOString(),build:{...state.builder},result:{calories:r.cooked.calories,protein:r.cooked.protein,fat:r.cooked.fat,carbs:r.cooked.carbs,overall:r.overall,meat:r.m.label,cheese:r.c.label}};state.savedBuilds.push(item);state.compareId=item.id;if(!state.favoriteBuildId)state.favoriteBuildId=item.id;syncChallenges(r);save();render();}
function loadBuild(id){const b=state.savedBuilds.find(x=>x.id===id);if(b){state.builder={...b.build};save();route("builder");}}
const preloadSet=new Set();function preload(i){const s=lessonSequence[i];if(!s||preloadSet.has(s.image))return;const im=new Image();im.src=preloadSrc(s.image);preloadSet.add(s.image)}function openStory(section,resume=false){let i=resume?Math.min(state.storyIndex,lessonSequence.length-1):Math.max(0,lessonSequence.findIndex(x=>x.sectionId===section)),last=0,sx=0,sy=0,tracking=false,story=document.createElement("section");story.className="story";const layer=pushLayer(()=>{state.storyIndex=i;state.maxStoryIndex=Math.max(state.maxStoryIndex,i);save();releaseWakeLock();story.remove();render();});acquireWakeLock();const close=()=>{state.storyIndex=i;state.maxStoryIndex=Math.max(state.maxStoryIndex,i);save();closeLayer(layer);releaseWakeLock();story.remove();render()},draw=()=>{const s=lessonSequence[i],pct=Math.round((i+1)/lessonSequence.length*100);story.innerHTML=`<div class="story-progress">${lessonSequence.map((_,n)=>`<i class="${n<=i?"active":""}"></i>`).join("")}</div><div class="story-meta">${esc(s.sectionTitle)} · ${i+1} / ${lessonSequence.length} · ${pct}%</div><button class="story-close">×</button><div class="story-slide">${img(s.image,s.title,true)}<div class="story-content"><p class="eyebrow" style="color:#fff">${esc(s.kicker)}</p><h2>${esc(s.title)}</h2><p>${esc(s.body)}</p></div><div class="story-tap"><button></button><button></button></div></div>`;$(".story-close",story).onclick=close;const [a,b]=$$(".story-tap button",story);a.onclick=()=>go(-1);b.onclick=()=>go(1);showTapHint(story);if(!story.dataset.introDone){story.dataset.introDone="1";story.insertAdjacentHTML("beforeend",tapIntroHTML());runTapIntro(story);}[i-1,i+1,i+2].forEach(preload);markViewed(i);state.storyIndex=i;state.maxStoryIndex=Math.max(state.maxStoryIndex,i);save()},go=d=>{const n=Date.now();if(n-last<250)return;last=n;if(d>0)tapHintAdvance(story);if(d>0&&i===lessonSequence.length-1){recomputeCompleted();state.storyIndex=0;save();closeLayer(layer);releaseWakeLock();story.remove();render()}else{i=clamp(i+d,0,lessonSequence.length-1);draw()}};story.addEventListener("touchstart",e=>{if(e.touches.length===1){tracking=true;sx=e.touches[0].clientX;sy=e.touches[0].clientY}},{passive:true});story.addEventListener("touchend",e=>{if(!tracking)return;tracking=false;const dx=e.changedTouches[0].clientX-sx,dy=e.changedTouches[0].clientY-sy;if(Math.abs(dx)>48&&Math.abs(dx)>Math.abs(dy)*1.4)go(dx<0?1:-1);else if(dy>90&&Math.abs(dy)>Math.abs(dx)*1.6)close()},{passive:true});document.body.appendChild(story);draw();}
document.addEventListener("input",e=>{const c=e.target.closest("[data-builder]");if(!c)return;const before={...state.builder},key=c.dataset.builder;state.builder[key]=c.type==="range"?Number(c.value):c.value;save();requestAnimationFrame(()=>{update();updateInsight(reason(before,state.builder,key))})});
document.addEventListener("change",e=>{const cmp=e.target.closest("[data-compare]");if(cmp){state.compareId=cmp.value;save();render()}const sk=e.target.closest("select[data-steak]");if(sk){state.steak.protocol[sk.dataset.steak]=sk.value;save();updateSteak();}});
document.addEventListener("input",e=>{const sk=e.target.closest("input[data-steak]");if(sk){state.steak.protocol[sk.dataset.steak]=sk.value;save();updateSteak();}});
document.addEventListener("click",e=>{const g=e.target.closest("[data-go]");if(g)route(g.dataset.go);const n=e.target.closest(".nav-item");if(n)route(n.dataset.route);const s=e.target.closest("[data-story]");if(s)openStory(s.dataset.story);if(e.target.closest("[data-resume]"))openStory(null,true);const o=e.target.closest("[data-opt]");if(o)optimize(o.dataset.opt);if(e.target.closest("[data-reset]")){state.builder={...defaultBuild};save();render()}if(e.target.closest("[data-save]"))saveBuild();if(e.target.closest("[data-cook-build]"))openCookBuild();const l=e.target.closest("[data-load]");if(l)loadBuild(l.dataset.load);const d=e.target.closest("[data-detail]");if(d)detail(d.dataset.detail);const recipe=e.target.closest("[data-recipe]");if(recipe)openRecipe(recipe.dataset.recipe);const ch=e.target.closest("[data-challenge]");if(ch)openChallengeSheet(ch.dataset.challenge);const sd=e.target.closest("[data-side]");if(sd)openSide(sd.dataset.side);const fl=e.target.closest("[data-flavour]");if(fl)openFlavour(fl.dataset.flavour);const adapt=e.target.closest("[data-adapt]");if(adapt)adaptRecipe(adapt.dataset.recipeId,adapt.dataset.adapt);if(e.target.closest("[data-next-step]")){if(state.completed.length<courses.length)openStory(null,true);else if(state.completedRecipes.length<1)document.querySelector(".recipe-section")?.scrollIntoView({behavior:"smooth"});else if(state.savedBuilds.length<1)route("builder");else route("profile")};const fav=e.target.closest("[data-favorite]");if(fav){state.favoriteBuildId=fav.dataset.favorite;save();render()}const ren=e.target.closest("[data-rename]");if(ren){const b=state.savedBuilds.find(x=>x.id===ren.dataset.rename);if(b){const name=prompt("Rename build",b.name);if(name&&name.trim()){b.name=name.trim().slice(0,36);save();render();}}}const del=e.target.closest("[data-delete]");if(del){const b=state.savedBuilds.find(x=>x.id===del.dataset.delete);if(b&&confirm(`Delete “${b.name}”? This cannot be undone.`)){state.savedBuilds=state.savedBuilds.filter(x=>x.id!==b.id);if(state.favoriteBuildId===b.id)state.favoriteBuildId=state.savedBuilds.at(-1)?.id||null;if(state.compareId===b.id)state.compareId=state.savedBuilds.at(-1)?.id||null;save();render();}}if(e.target.closest("[data-steak-reset]")){state.steak.protocol={...defaultProtocol};save();render()}if(e.target.closest("[data-cook-steak]"))openCookSteak();if(e.target.closest("[data-save-protocol]"))saveProtocol();const lp=e.target.closest("[data-load-protocol]");if(lp){const b=state.steak.savedProtocols.find(x=>x.id===lp.dataset.loadProtocol);if(b){state.steak.protocol={...defaultProtocol,...b.protocol};save();route("builder");}}const dp=e.target.closest("[data-delete-protocol]");if(dp){const b=state.steak.savedProtocols.find(x=>x.id===dp.dataset.deleteProtocol);if(b&&confirm(`Delete “${b.name}”? This cannot be undone.`)){state.steak.savedProtocols=state.steak.savedProtocols.filter(x=>x.id!==b.id);save();render();}}});
// RC2-m10: keep browser chrome colour in sync with the active theme.
function syncThemeColor(){const meta=document.querySelector("#themeColorMeta");if(meta)meta.content=state.theme==="dark"?"#090a0b":"#f4f1ea";}
document.querySelector("#themeToggle").onclick=()=>{state.theme=document.documentElement.dataset.theme==="dark"?"light":"dark";document.documentElement.dataset.theme=state.theme;save();syncThemeColor()};syncThemeColor();if("serviceWorker" in navigator)navigator.serviceWorker.register("./sw.js").catch(()=>{});route(state.route);if(!state.discipline)openChooser(false);setTimeout(()=>[state.storyIndex,state.storyIndex+1].forEach(preload),700);
// FP-03: dismiss the launch screen once the first render has painted; never hold beyond ~1s.
(()=>{const splash=document.querySelector("#splash");if(!splash)return;const leave=()=>{if(splash.dataset.left)return;splash.dataset.left="1";splash.classList.add("leaving");setTimeout(()=>splash.remove(),450);};requestAnimationFrame(()=>requestAnimationFrame(leave));setTimeout(leave,1000);})();
